INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$65be7e5d-17ce-44e9-87a1-b59a47667c39$tag$, $tag$2026010800125$tag$, $tag$Mayra (5511944619231)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Boa Tarde","time":"08/01/2026 13:58:02"},{"role":"client","text":"🌟 Boa tarde Mayra! Que alegria ter você aqui com a gente! 🙌","time":"08/01/2026 13:58:04"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"08/01/2026 13:58:08"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"08/01/2026 13:58:13"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"08/01/2026 13:58:17"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"08/01/2026 13:58:23"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"08/01/2026 13:58:29"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"08/01/2026 13:58:29"},{"role":"client","text":"Sim, concordo","time":"08/01/2026 14:04:02"},{"role":"client","text":"✅ Obrigado, Mayra! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"08/01/2026 14:04:03"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"08/01/2026 14:04:07"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"08/01/2026 14:05:55"},{"role":"client","text":"Olá! Mayra!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"08/01/2026 14:05:55"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"08/01/2026 14:05:59"},{"role":"client","text":"Falar com um atendente","time":"08/01/2026 14:06:13"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"08/01/2026 14:06:14"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"08/01/2026 14:07:17"},{"role":"client","text":"Oi Karina boa tarde","time":"08/01/2026 14:07:31"},{"role":"client","text":"Eu iniciei a inscrição da Pós em Educação Cristã Clássica com vocês ano passado, mas, precisei cancelar por um motivo pessoal","time":"08/01/2026 14:07:57"},{"role":"client","text":"Agora, gostaria de retomar","time":"08/01/2026 14:08:02"},{"role":"client","text":"Mas, na ocasião eu entrei com um grupo de professoras e obtive um desconto. Gostaria de saber se conseguem me ajudar. Sou professora de Artes da Trinitas em São Paulo, por isso gostaria de saber do desconto","time":"08/01/2026 14:12:06"},{"role":"agent","text":"*Karina Pimentel:* Olá!","time":"08/01/2026 14:57:01","feedback":"🤝 Humanização & Rapport: Ótimo início. Lembre-se de primeiro entender o momento do cliente antes de qualquer script."},{"role":"agent","text":"*Karina Pimentel:* Me informe seu nome completo por gentileza!","time":"08/01/2026 14:58:11","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Mayra Campagnolli Macedo","time":"08/01/2026 14:58:54"},{"role":"agent","text":"*Karina Pimentel:* A senhora chegou a cursar alguma disciplina? ","time":"08/01/2026 15:25:01","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Não","time":"08/01/2026 15:28:19"},{"role":"client","text":"Só me inscrevi e precisei sair","time":"08/01/2026 15:28:28"},{"role":"agent","text":"*Karina Pimentel:* Nada","time":"08/01/2026 15:28:31","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Nadinha","time":"08/01/2026 15:28:55"},{"role":"agent","text":"*Karina Pimentel:* Vou verificar com meu superior se conseguimos colocar a senhora na turma de Abril de 2026.","time":"08/01/2026 15:31:12","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Obrigada","time":"08/01/2026 15:32:28"},{"role":"agent","text":"*Karina Pimentel:* Senhora pagava R$ 174,24?","time":"08/01/2026 15:32:34","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Deixa eu verificar","time":"08/01/2026 15:32:51"},{"role":"client","text":"Isso mesmo","time":"08/01/2026 15:33:53"},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/695ff897a599b1f56007f9ac)","time":"08/01/2026 15:33:59"},{"role":"agent","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/695ffc2656b3b894960be5e0)","time":"08/01/2026 15:49:10","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Pode sim, mas, aí como será somente em abril, farei a inscrição em fevereiro, tudo bem ?","time":"08/01/2026 15:56:25"},{"role":"client","text":"Agradeço a gentileza do desconto","time":"08/01/2026 15:56:41"},{"role":"agent","text":"*Karina Pimentel:* Pode fazer já, e as próximas começaram a ser pagas em Abril.","time":"08/01/2026 16:16:44","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* 🎁 Cupom de Desconto ECC: *BOLSA60*\n\n📌 Realize sua matrícula no link: bit.ly/InscricaoPosECC2024\n\n✅ Assim que você preencher os seus dados, o sistema disponibilizará o seu contrato para aceitação e o pagamento da primeira parcela, que pode ser feito por cartão ou boleto.","time":"08/01/2026 16:17:09","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Feito! Vou pagar o boleto e está tudo ok","time":"08/01/2026 16:41:27"},{"role":"agent","text":"*Karina Pimentel:* Benção!","time":"08/01/2026 16:44:33","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Qualquer duvida estou a disposição!\n","time":"08/01/2026 16:44:44","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Obrigada Karina 🩷","time":"08/01/2026 16:45:01"},{"role":"client","text":"Atendimento Finalizado!\n\nMayra, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"08/01/2026 17:19:50"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"08/01/2026 17:19:51"},{"role":"client","text":"5","time":"08/01/2026 17:20:10"},{"role":"client","text