INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$4eca22a1-8aae-44e0-9063-b8f3406c1401$tag$, $tag$2026010700098$tag$, $tag$Edriane N Lira (5583986774527)$tag$, NULL, $tag$Tyago Mendes$tag$, $tag$[{"role":"client","text":"Não porque há um equívoco enorme dessa instituição dizendo que tenho débitos pendente de uma pós que nunca fiz matrícula más apenas fiquei aguardando um desconto na época para fazer inscrição em 2024 que não foi dado e como não foi possível o desconto na época porque havia passado o prazo, não realizei a matrícula deixando para um tempo que fosse possível","time":"07/01/2026 10:41:49"},{"role":"client","text":"🌟 Bom dia Edriane N Lira! Que alegria ter você aqui com a gente! 🙌","time":"07/01/2026 10:41:50"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"07/01/2026 10:41:53"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"07/01/2026 10:41:57"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"07/01/2026 10:42:05"},{"role":"client","text":"Como é que devo algo que não assinei contrato","time":"07/01/2026 10:42:24"},{"role":"client","text":"Ops, não consegui entender sua mensagem. 😕 \n\nPor favor, selecione  *a opção desejada*  no menu anterior.\n","time":"07/01/2026 10:42:25"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"07/01/2026 10:42:26"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"07/01/2026 10:42:33"},{"role":"client","text":"Olá! Edriane N Lira!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"07/01/2026 10:42:34"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"07/01/2026 10:42:38"},{"role":"client","text":"Falar com um atendente","time":"07/01/2026 10:42:56"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"07/01/2026 10:42:57"},{"role":"client","text":"Cobrança ilegal","time":"07/01/2026 10:44:00"},{"role":"client","text":"Thayanne Sales transferiu o atendimento para a equipe FICV - SECRETARIA","time":"07/01/2026 11:00:43"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Tyago Mendes","time":"07/01/2026 13:52:13"},{"role":"agent","text":"*Tyago Mendes:* Boa tarde, senhora","time":"07/01/2026 13:52:23","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Tyago Mendes:* em que posso lhe ajudar?","time":"07/01/2026 13:52:28","feedback":"⚠️ Pergunta Genérica: Evite perguntas que podem ser respondidas com \"não\". Tente: \"Qual sua maior motivação para estudar hoje?\""},{"role":"client","text":"Estou querendo fazer minha matrícula na pós de Novo Testamento e na hora consta pendências com a FICV. Acredito que deva ser o mesmo problema de 2024 antes JÁ conversado  e segundo c Victor do financeiro, RESOLVEU: Havia um equívoco no sistema constando que eu era aluna de pós quando na verdade SÓ havia conversado com uma funcionária chamada Karina pedindo para me enviar as promoções para alunos da FICV concluintes de Teologia. Eu não cheguei a firmar contrato nem pagar inscrição porque não me deram o desconto prometido por causa do término da promoção de 70% . Me ofereceu 50% mais disse que iria aguardar por enquanto até colocar uma pendências médicas em dia. Veja abaixo: 👇","time":"07/01/2026 14:41:38"},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/695e9af6141e99d25601d6b5)","time":"07/01/2026 14:42:14"},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/695e9b28c76fee46ca00a310)","time":"07/01/2026 14:43:04"},{"role":"client","text":"Karina perguntou: &quot;Vamos realizar sua matrícula?&quot; Só que prefiro esperar.","time":"07/01/2026 14:43:46"},{"role":"client","text":"Se não me falha a memória falei pessoalmente com Victor do financeiro e ele disse para não me preocupar que cancelaria esse equívoco 😞","time":"07/01/2026 14:45:34"},{"role":"client","text":"Meu Deus. Como é que vocês não perceberam essa falha? É constrangedor essa situação. Eu não me escrevi em nenhum curso após concluir Teologia, não firmei contrato nenhum e muito menos devo nada a FICV","time":"07/01/2026 14:49:54"},{"role":"agent","text":"*Tyago Mendes:* Vou confirmar com o Victor e lhe dou um retorno em breve","time":"07/01/2026 14:51:30","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Resolvam isso pelo amor de Deus. Tenho como puxar extratos bancários, Pix e cartão de crédito como evidências de que não contraí essa dívida com os senhores 🙌","time":"07/01/2026 14:51:33"},{"role":"client","text":"Faça isso pelo amor de Deus. Espero que ele lembre desse fato porque faz um ano do ocorrido. Apesar de que vocês devem ter no acervo de registro financeiro que não fiz matrícula em pós, não assinei contrato e nem muito menos participei de aula nenhuma... 🙌","time":"07/01/2026 14:54:13"},{"role":"agent","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/695ea176c621e9517a0d0856)","time":"07/01/2026 15:09:58","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Tyago Mendes transferiu o atendimento para a equipe FICV - COMERCIAL","time":"08/01/2026 08:26:22"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"08/01/2026 08:31:44"},{"role":"client","text":"*Thayanne Sales:* No que posso lhe ajudar?","time":"08/01/2026 08:31:52"},{"role":"client","text":"Bom dia","time":"08/01/2026 09:31:08"},{"role":"client","text":"Desejo fazer inscrição na pós de Novo Testamento","time":"08/01/2026 09:31:11"},{"role":"client","text":"*Thayanne Sales:* Vou lhe enviar as informações sobre o curso ","time":"08/01/2026 09:31:58"},{"role":"client","text":"*Thayanne Sales:* *Pós-graduação em Teologia Bíblica e Exegética do Novo Testamento*\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 440h.\n\n*DISCIPLINAS*\nContamos com um total de 12 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"08/01/2026 09:32:12"},{"role":"client","text":"*Thayanne Sales:*   *Teologia Bíblica e Exegética do Novo Testamento* - Disciplinas do Curso: \n\nCONTEXTO HISTÓRICO DO NOVO TESTAMENTO\nPeríodo Interbíblico e a Formação do Contexto do Novo Testamento\nCosmovisão Judaica, Helênica e Romana do Primeiro Século\nArqueologia Aplicada ao Novo Testamento\n\nTEOLOGIA BÍBLICA DO NOVO TESTAMENTO\nTeologia Bíblica e Exegética dos Evangelhos de Mateus e Marcos\nTeologia Bíblica e Exegética do Evangelho de Lucas e Atos\nTeologia Bíblica e Exegética do Evangelho de João e Suas Cartas\nTeologia Bíblica e Exegética dos Escritos Paulinos I\nTeologia Bíblica e Exegética dos Escritos Paulinos II\nTeologia Bíblica e Exegética das Epístolas Gerais\n﻿Teologia Bíblica e Exegética do Livro do Apocalipse\n\nTEOLOGIA APLICADA À REALIDADE\nFerramentas Exegéticas para Interpretação do Novo Testamento\nTemas Contemporâneos à Luz da Teologia do Novo Testamento\n\nObs: Professores sujeitos a alterações. ","time":"08/01/2026 09:32:19"},{"role":"client","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Novo Testamento está em 16 mensalidades de *R$ 359,37*. Esta com condições especiais com esta com 50% de desconto e as mensalidades ficam por R$ 179,68\n\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril/2026. \n\n🎁 Cupom de Desconto Novo Testamento: *BOLSA50*\n\n📌 Realize sua matrícula no link: https://c95716.mannesoftprime.com.br/processo_seletivo/?PS=PROCESSO_SELETIVO_23\n\n*Mas lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. \n\n*Assim que fizer sua matricula e  efetuar o pagamento, me envia o comprovante de pagamento para eu poder da baixa no sistema.*","time":"08/01/2026 09:32:52"},{"role":"client","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nConseguiu fazer a sua matricula?","time":"09/01/2026 08:10:36"},{"role":"client","text":"Atendimento Finalizado!\n\nEdriane N Lira, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"09/01/2026 10:50:30"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"09/01/2026 10:50:31"},{"role":"client","text":"Edriane N Lira, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"09/01/2026 11:05:32"}]$tag$, $tag$2026-01-07 10:41:49+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 10, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
