INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$ffb2f18b-b1cd-41fa-8fb4-9f98894bc22f$tag$, $tag$2026010800176$tag$, $tag$Mariana Trevisani (5532991458742)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Educacao Crista Classica e quero mais informações.","time":"08/01/2026 16:50:21"},{"role":"client","text":"🌟 Boa tarde Mariana Trevisani! Que alegria ter você aqui com a gente! 🙌","time":"08/01/2026 16:50:21"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"08/01/2026 16:50:25"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"08/01/2026 16:50:29"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"08/01/2026 16:50:36"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"08/01/2026 16:51:17"},{"role":"client","text":"Olá! Mariana Trevisani!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"08/01/2026 16:51:18"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"08/01/2026 16:51:22"},{"role":"client","text":"Saber sobre os cursos","time":"08/01/2026 16:51:34"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"08/01/2026 16:51:38"},{"role":"client","text":"Pós-Graduação","time":"08/01/2026 16:51:47"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"08/01/2026 16:51:51"},{"role":"client","text":"Educação Cristã Clássica","time":"08/01/2026 16:52:02"},{"role":"client","text":"Formação exclusiva para educadores e líderes que desejam ensinar com base na tradição cristã clássica.\n\n 📚 Cosmovisão cristã sólida\n 📌 Leituras fundamentais do pensamento ocidental\n 🧭 Formação para escolas cristãs ou ministérios educacionais\n 🗓️ Matrículas abertas para agosto","time":"08/01/2026 16:52:02"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"08/01/2026 16:52:06"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"08/01/2026 16:52:36"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"08/01/2026 16:52:37"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"08/01/2026 17:03:16"},{"role":"agent","text":"*Thayanne Sales:* Vou lhe enviar as informações sobre o curso","time":"08/01/2026 17:03:25","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Olá Thayanne, tudo bem?","time":"08/01/2026 17:03:33"},{"role":"client","text":"Agradeço","time":"08/01/2026 17:03:37"},{"role":"agent","text":"*Thayanne Sales:* *Pós-graduação em Educação Cristã Clássica*.\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 400h.\n\n*DISCIPLINAS*\nContamos com um total de 10 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"08/01/2026 17:03:41","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* *Educação Cristã Clássica* - Disciplinas do Curso:\n\nBase: Filosófica Teológica\nCosmovisão Cristã e Filosofia Reformada – Ms. Vinicius Pimentel\nFundamentos da Pedagogia Cristã – Ms. Igor Miguel\nA Paideia de Deus (Educação Pactual) – Ms. Rodrigo Brotto\n\nBase: Histórica Pedagógica Clássica&nbsp;\nHistória da Educação Clássica – Ms. Lucas Evangelista\nFundamentos Pedagógicos das Sete Artes Liberais – Ms. Rodrigo Brotto\nVerdade, Bondade e Beleza: A Formação do Imaginário – Ms. Raquel Van De Burgt\n\nBase: Metodológica Cristã Clássica\nAplicando o Trivium no Contexto Educacional – Ms. Renata Costa\nAprendendo a Ler Classicamente (Alfabetização Clássica) – Esp. Leandro Ribeiro\nDisciplina na Educação (Pastoreando o Coração da Criança) – Ms. Kenneth V. Trotter\nDesenvolvimento do Currículo - Kim Bedinfield\n\nObs: Professores sujeitos a alterações. ","time":"08/01/2026 17:03:47","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Educação Cristã Clássica está em 16 mensalidades de *R$ 479,16*. Esta com condições especiais com 50% de desconto e as mensalidades está por R$ 239,58 \n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para abril/2026.\n\n\n🎁 Cupom de Desconto ECC: *BOLSA50*\n📌 Realize sua matrícula no link: https://c95716.mannesoftprime.com.br/processo_seletivo/?PS=PROCESSO_SELETIVO_19\n\n\n*Mas lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. \n\n*Assim que fizer sua matricula e  efetuar o pagamento, me envia o comprovante de pagamento para eu poder da baixa no sistema.*","time":"08/01/2026 17:03:52","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"agent","text":"*Thayanne Sales:* Qualquer dúvida é só chamar ","time":"08/01/2026 17:04:00","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Agradeço!","time":"08/01/2026 17:04:33"},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nConseguiu fazer a sua matricula?","time":"09/01/2026 08:12:12","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nMariana Trevisani, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"09/01/2026 17:46:15"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"09/01/2026 17:46:16"},{"role":"client","text":"Mariana Trevisani, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"09/01/2026 18:01:16"}]$tag$, $tag$2026-01-08 16:50:21+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 6, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, times