INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$2daa535f-9c6d-4ef0-8729-b1a4ae604ea3$tag$, $tag$2026010900054$tag$, $tag$Márcio Dantas Costa (558179162452)$tag$, NULL, $tag$Anderson Brito$tag$, $tag$[{"role":"client","text":"Olá","time":"09/01/2026 10:47:44"},{"role":"client","text":"🌟 Bom dia Márcio Dantas Costa! Que alegria ter você aqui com a gente! 🙌","time":"09/01/2026 10:47:45"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"09/01/2026 10:47:49"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"09/01/2026 10:47:53"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"09/01/2026 10:47:59"},{"role":"client","text":"Quero fazer uma nova matrícula","time":"09/01/2026 10:48:01"},{"role":"client","text":"Ops, não consegui entender sua mensagem. 😕 \n\nPor favor, selecione  *a opção desejada*  no menu anterior.\n","time":"09/01/2026 10:48:02"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"09/01/2026 10:48:03"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"09/01/2026 10:48:35"},{"role":"client","text":"Olá! Márcio Dantas Costa!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"09/01/2026 10:48:37"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"09/01/2026 10:48:41"},{"role":"client","text":"Sou aluno e quero ajuda","time":"09/01/2026 10:48:59"},{"role":"client","text":"Claro! Vamos te ajudar o mais rápido possível. Selecione no menu abaixo qual tipo de ajuda você precisa:","time":"09/01/2026 10:49:04"},{"role":"client","text":"Assuntos pedagógicos","time":"09/01/2026 10:49:24"},{"role":"client","text":"Perfeito! Qual curso você está matriculado(a)?","time":"09/01/2026 10:49:28"},{"role":"client","text":"Graduação","time":"09/01/2026 10:49:40"},{"role":"client","text":"Coordenação Pedagógica Graduação","time":"09/01/2026 10:49:44"},{"role":"client","text":"Teologia (EAD)","time":"09/01/2026 10:50:07"},{"role":"client","text":"Perfeito. Escolha uma opção na lista abaixo sobre o que você deseja falar","time":"09/01/2026 10:50:08"},{"role":"client","text":"Disciplinas em geral \n Mediação Pedagógica - Disciplinas em geral","time":"09/01/2026 10:50:24"},{"role":"client","text":"Certo! 🙌\n Estamos localizando um atendente para falar com você. Enquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"09/01/2026 10:50:25"},{"role":"client","text":"Fazer nova matrícula","time":"09/01/2026 10:52:28"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Anderson Brito","time":"09/01/2026 11:50:59"},{"role":"agent","text":"*Anderson Brito:* Olá, Márcio!","time":"09/01/2026 11:51:09","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Anderson Brito:* Você é aluno de teologia EAD? deseja fazer matricula em qual curso?","time":"09/01/2026 11:51:28","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Olá","time":"09/01/2026 13:45:14"},{"role":"client","text":"Tem algum desconto para membros da igreja Rio de Recife ?","time":"09/01/2026 13:45:37"},{"role":"client","text":"Anderson Brito transferiu o atendimento para a equipe FICV - COMERCIAL","time":"12/01/2026 09:24:39"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"12/01/2026 10:22:37"},{"role":"client","text":"*Thayanne Sales:* Olá Bom dia me chamo Thayanne Sales da Cidade Viva! \n","time":"12/01/2026 10:22:44"},{"role":"client","text":"Olá","time":"12/01/2026 10:45:46"},{"role":"client","text":"*Thayanne Sales:* Qual o curso que deseja informações ?","time":"12/01/2026 10:46:21"},{"role":"client","text":"Teologia das","time":"12/01/2026 13:48:49"},{"role":"client","text":"Ead Teologia","time":"12/01/2026 13:49:16"},{"role":"client","text":"*Thayanne Sales:* Olá Bom dia!\n\nVou lhe enviar as informações sobre o curso","time":"13/01/2026 08:25:26"},{"role":"client","text":"*Thayanne Sales:* A nossa Graduação em Teologia EAD é Bacharelado reconhecido pelo MEC ( bit.ly/3LlEgJS ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"13/01/2026 08:25:28"},{"role":"client","text":"*Thayanne Sales:* Segue a matriz curricular do curso de Teologia bit.ly/3xljQgl","time":"13/01/2026 08:25:33"},{"role":"client","text":"*Thayanne Sales:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 319,76 por mês! 🎉 Usando o cupom *BOLSA20*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 319,76 = R$ 1.918,56\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"13/01/2026 08:25:39"},{"role":"client","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nRealize a matrícula de acordo com a sua forma de ingresso, basta acessar o link correspondente abaixo:\n\n1 - Aproveitamento do ENEM:\nbit.ly/FICV-Enem\n\n2 - Vestibular Agendado:\nbit.ly/FICV-Vestibular\n\n3 - Seleção de Graduados:\nbit.ly/FICV-Graduados\n\n📝 Após preencher seus dados, o sistema disponibilizará o pagamento da primeira parcela e o contrato para aceite. Não há cobrança de matrícula.😊","time":"13/01/2026 08:25:48"},{"role":"client","text":"Atendimento Finalizado!\n\nMárcio Dantas Costa, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"13/01/2026 14:06:37"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"13/01/2026 14:06:37"},{"role":"client","text":"Márcio Dantas Costa, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"13/01/2026 14:21:38"}]$tag$, $tag$2026-01-09 10:47:44+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 9, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, crea