INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$5c83c640-e9af-419f-816e-cac1c888746b$tag$, $tag$2026010900162$tag$, $tag$Arthur (5575991815007)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Sim, concordo","time":"09/01/2026 21:25:34"},{"role":"client","text":"🌟 Boa noite Arthur! Que alegria ter você aqui com a gente! 🙌","time":"09/01/2026 21:25:35"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"09/01/2026 21:25:39"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"09/01/2026 21:25:43"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"09/01/2026 21:25:47"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"09/01/2026 21:25:53"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"09/01/2026 21:25:59"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"09/01/2026 21:25:59"},{"role":"client","text":"Sim, concordo","time":"09/01/2026 21:31:49"},{"role":"client","text":"✅ Obrigado, Arthur! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"09/01/2026 21:31:50"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"09/01/2026 21:31:54"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"09/01/2026 21:32:26"},{"role":"client","text":"Olá! Arthur!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"09/01/2026 21:32:26"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"09/01/2026 21:32:30"},{"role":"client","text":"Saber sobre os cursos","time":"09/01/2026 21:32:48"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"09/01/2026 21:32:52"},{"role":"client","text":"Pós-Graduação","time":"09/01/2026 21:33:38"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"09/01/2026 21:33:43"},{"role":"client","text":"Liderança Cristã","time":"09/01/2026 21:34:01"},{"role":"client","text":"Lidere com sabedoria, integridade e propósito.\n 🧭 Curso voltado para líderes de igrejas, ministérios e organizações cristãs\n 🌍 Temas como discipulado, liderança servidora e gestão de equipes\n 📅 Ainda dá tempo de começar este semestre!\n","time":"09/01/2026 21:34:02"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"09/01/2026 21:34:06"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"09/01/2026 21:34:16"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"09/01/2026 21:34:17"},{"role":"client","text":"Ok","time":"10/01/2026 11:56:42"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"12/01/2026 08:32:34"},{"role":"agent","text":"*Karina Pimente