INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$ff60623c-89d4-401d-8fab-718ff8218d50$tag$, $tag$2026011100024$tag$, $tag$Nayara Santos (5519989065591)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Sim, concordo","time":"11/01/2026 17:06:37"},{"role":"client","text":"🌟 Boa tarde Nayara Santos! Que alegria ter você aqui com a gente! 🙌","time":"11/01/2026 17:06:38"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"11/01/2026 17:06:42"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"11/01/2026 17:06:46"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"11/01/2026 17:06:50"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"11/01/2026 17:06:56"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"11/01/2026 17:07:02"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"11/01/2026 17:07:03"},{"role":"client","text":"Sim, concordo","time":"11/01/2026 17:07:12"},{"role":"client","text":"✅ Obrigado, Nayara Santos! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"11/01/2026 17:07:13"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"11/01/2026 17:07:17"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"11/01/2026 17:07:30"},{"role":"client","text":"Olá! Nayara Santos!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"11/01/2026 17:07:31"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"11/01/2026 17:07:35"},{"role":"client","text":"Saber sobre os cursos","time":"11/01/2026 17:07:44"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"11/01/2026 17:07:48"},{"role":"client","text":"Pós-Graduação","time":"11/01/2026 17:08:01"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"11/01/2026 17:08:05"},{"role":"client","text":"Educação Cristã Clássica","time":"11/01/2026 17:08:14"},{"role":"client","text":"Formação exclusiva para educadores e líderes que desejam ensinar com base na tradição cristã clássica.\n\n 📚 Cosmovisão cristã sólida\n 📌 Leituras fundamentais do pensamento ocidental\n 🧭 Formação para escolas cristãs ou ministérios educacionais\n 🗓️ Matrículas abertas para agosto","time":"11/01/2026 17:08:15"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"11/01/2026 17:08:19"},{"role":"client","text":"Voltar ao menu \n Voltar ao menu principal","time":"11/01/2026 17:08:40"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"11/01/2026 17:08:41"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"11/01/2026 17:08:50"},{"role":"client","text":"Olá! Nayara Santos!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"11/01/2026 17:08:51"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"11/01/2026 17:08:54"},{"role":"client","text":"Saber sobre os cursos","time":"11/01/2026 17:09:03"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"11/01/2026 17:09:07"},{"role":"client","text":"Cursos livres","time":"11/01/2026 17:09:16"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você. \n\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"11/01/2026 17:09:16"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"11/01/2026 17:09:17"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"12/01/2026 10:12:47"},{"role":"agent","text":"*Thayanne Sales:* No que posso lhe ajudar?","time":"12/01/2026 10:13:29","feedback":"⚠️ Pergunta Genérica: Evite perguntas que podem ser respondidas com \"não\". Tente: \"Qual sua maior motivação para estudar hoje?\""},{"role":"client","text":"Atendimento Finalizado!\n\nNayara Santos, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"13/01/2026 08:26:20"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"13/01/2026 08:26:21"},{"role":"client","text":"Nayara Santos, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"13/01/2026 08:41:22"}]$tag$, $tag$2026-01-11 17:06:37+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 1, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
