INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$bd9e7481-9588-4c7e-828b-02cd11694252$tag$, $tag$2026011200133$tag$, $tag$🌻 (5514998918825)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, vim pelo Instagram e quero mais informações","time":"12/01/2026 18:55:40"},{"role":"client","text":"🌟 Boa noite 🌻! Que alegria ter você aqui com a gente! 🙌","time":"12/01/2026 18:55:41"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"12/01/2026 18:55:45"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"12/01/2026 18:55:49"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"12/01/2026 18:55:53"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"12/01/2026 18:55:59"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"12/01/2026 18:56:04"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"12/01/2026 18:56:05"},{"role":"client","text":"Sim, concordo","time":"12/01/2026 18:56:45"},{"role":"client","text":"✅ Obrigado, 🌻! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"12/01/2026 18:56:46"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"12/01/2026 18:56:50"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"12/01/2026 18:57:15"},{"role":"client","text":"Olá! 🌻!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"12/01/2026 18:57:16"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"12/01/2026 18:57:19"},{"role":"client","text":"Saber sobre os cursos","time":"12/01/2026 18:57:33"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"12/01/2026 18:57:37"},{"role":"client","text":"Graduação","time":"12/01/2026 18:57:48"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"12/01/2026 18:57:52"},{"role":"client","text":"Teologia (EAD)","time":"12/01/2026 18:58:05"},{"role":"client","text":"📚 A graduação EAD em Teologia é ideal para quem busca flexibilidade e profundidade bíblica onde estiver.\n✨ Estude no seu ritmo, com uma formação teológica séria e completa:\n 🧠 Cosmovisão Cristã\n 🔠 Grego e Hebraico\n 💻 Plataforma moderna e aulas dinâmicas\n 🤝 Mentoria, iniciação científica e prática ministerial\n","time":"12/01/2026 18:58:05"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"12/01/2026 18:58:09"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"12/01/2026 18:58:28"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"12/01/2026 18:58:29"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"12/01/2026 18:58:29"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"13/01/2026 08:44:29"},{"role":"agent","text":"*Thayanne Sales:* A nossa Graduação em Teologia EAD é Bacharelado reconhecido pelo MEC ( bit.ly/3LlEgJS ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"13/01/2026 08:44:39","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Segue a matriz curricular do curso de Teologia bit.ly/3xljQgl","time":"13/01/2026 08:44:46","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 319,76 por mês! 🎉 Usando o cupom *BOLSA20*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 319,76 = R$ 1.918,56\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"13/01/2026 08:44:58","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nRealize a matrícula de acordo com a sua forma de ingresso, basta acessar o link correspondente abaixo:\n\n1 - Aproveitamento do ENEM:\nbit.ly/FICV-Enem\n\n2 - Vestibular Agendado:\nbit.ly/FICV-Vestibular\n\n3 - Seleção de Graduados:\nbit.ly/FICV-Graduados\n\n📝 Após preencher seus dados, o sistema disponibilizará o pagamento da primeira parcela e o contrato para aceite. Não há cobrança de matrícula.😊","time":"13/01/2026 08:45:02","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\n🌻, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"14/01/2026 08:12:48"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"14/01/2026 08:12:49"},{"role":"client","text":"🌻, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"14/01/2026 08:27:50"}]$tag$, $tag$2026-01-12 18:55:40+00$tag$, FALSE, FALSE, 8, $tag$2026-03-01 16:46:57.607947+00$tag$, 9, 10, 10, 2, 9, 4, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$appro