INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$c4861337-cdf8-4b3e-a7c4-8dd6b25f9c25$tag$, $tag$2026011300013$tag$, $tag$rodolfo (5583993926132)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Direito e quero mais informações.","time":"13/01/2026 08:41:47"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"13/01/2026 08:41:48"},{"role":"client","text":"Obg","time":"13/01/2026 08:42:03"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"13/01/2026 08:48:16"},{"role":"agent","text":"*Thayanne Sales:* *Bacharelado em Direito*\n\n*GRADUAÇÃO COM COSMOVISÃO CRISTÃ*\nValorização do Direito clássico, sem viés ideológico, o Direito tratado numa cosmovisão cristã.\n\n*NOTA MÁXIMA NO MEC*\nGraduação com a maior avaliação junto ao MEC, conceito 05 estrelas ( *bit.ly/3LlEgJS* ) com duração de 5 anos. \n\n*PRÁTICA JURÍDICA*\nÚnico curso no Brasil com vivência de prática jurídica do primeiro ao décimo período.\n\n*NÚCLEO*\nPrimeiro e único núcleo de prática jurídica em Lei Geral de Proteção de Dados (LGPD).\n\n*VOCAÇÃO*\nEspecialização durante a graduação com disciplinas optativas nas áreas: \n\na) Serviço Público; \nb) Advocacia Empreendedora; \nc) Academia\n\n*BIBLIOTECA DIGITAL*\nRevista dos Tribunais online e a Biblioteca Digital Proview da Revista dos Tribunais. Kindles com assinatura Unlimited.\n\n*AULAS PRESENCIAIS*\nDe segunda à sexta, das 19h às 22h - goo.gl/maps/tb5occMvgJGHsjwz9.","time":"13/01/2026 08:48:30","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Segue a matriz curricular do curso de Direito *bit.ly/3SpepqX*","time":"13/01/2026 08:48:36","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* A mensalidade da Graduação em Direito está R$ 1.407,95. \n\n🤩 Estamos com uma condição excepcional, desconto de 60% na pontualidade durante toda graduação que ficará o valor de R$ 563,18.\n\nNão há taxa de matrícula, sendo a primeira mensalidade paga no ato da inscrição, e as demais mensalidades pagas até o dia 10 de cada mês.\n\n🌟 Valor promocional: (Semestralidade R$ 3.379,08).\n⚠️ Valor mensal está sujeito a mudança de acordo a data de matrícula:\n\n Matrículas realizadas até em JANEIRO: 6 mensalidades de R$ 563,18 = R$ 3.379,08\n Matrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 675,81 = R$ 3.379,08\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 844,77 = R$ 3.3.79,08\n\nInício das aulas em Fevereiro de 2026 📚📖💻","time":"13/01/2026 08:48:59","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nRealize a matrícula de acordo com a sua forma de ingresso, basta acessar o link correspondente abaixo:\n\n1 - Aproveitamento do ENEM:\nbit.ly/FICV-Enem\n\n2 - Vestibular Agendado:\nbit.ly/FICV-Vestibular\n\n3 - Seleção de Graduados:\nbit.ly/FICV-Graduados\n\n📝 Após preencher seus dados, o sistema disponibilizará o pagamento da primeira parcela e o contrato para aceite. Não há cobrança de matrícula.😊","time":"13/01/2026 08:49:04","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Graduação \n24 meses\n*SUPERIOR DE TECNOLOGIA EM GESTÃO DE SERVIÇOS JUDICIAIS E NOTARIAIS*\nEAD\n \n\nO curso de Gestão de Serviços Judiciais e Notariais é fundamental para quem busca otimizar a administração de escritórios de advocacia, departamentos jurídicos e cartórios, sendo essencial para a eficiência do setor legal.\n \n \nAo longo da graduação, você terá acesso a conteúdos de ponta e experiências que estimulam o raciocínio organizado, a atenção à legislação e a visão administrativa. Você vai desenvolver competências cruciais para planejar, organizar e gerir rotinas administrativas, financeiras e de pessoal no ambiente jurídico.\n \n \nEstará preparado para atuar com excelência em diferentes contextos, desde a gestão de processos e documentos (compliance) e a logística de audiências até o uso de tecnologia (jurimetria), transformando ideias em serviços jurídicos e notariais rápidos, transparentes e em estrita conformidade legal.","time":"13/01/2026 08:51:17"},{"role":"client","text":"Vcs tem esse curso aí","time":"13/01/2026 08:51:28"},{"role":"agent","text":"*Thayanne Sales:* Aqui estão os cursos disponíveis:\n\nGraduações\n\n* Direito (Presencial)\n* Teologia (presencial e EAD)\n\nPós-Graduações\n\n* Educação Cristã Clássica (EAD) - 16 meses\n* Novo Testamento (EAD) - 16 meses\n* Liderança Cristã (EAD) - 16 meses\n* Ciência Política (EAD) - 16 meses\n* Missiologia Urbana (EAD) - 16 meses\n* Teologia Sistemática (EAD) - 16 meses\n* Gestão Escolar (EAD) - 16 meses\n* Psicopedagogia (EAD) - 18 meses\n*Psicoteologia (EAD) - 16 meses","time":"13/01/2026 08:52:09","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/6966324a9af2f0fcb50f4f16)","time":"13/01/2026 08:53:46"},{"role":"agent","text":"*Thayanne Sales:* São pós-gradações","time":"13/01/2026 09:05:32","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Você precisa ter qualquer  graduação reconhecida pelo MEC","time":"13/01/2026 09:05:52","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/696635494a72a34cb40a5b1d)","time":"13/01/2026 09:06:33"},{"role":"agent","text":"*Thayanne Sales:* Tecnólogo não ","time":"13/01/2026 09:13:47","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Mas temos cursos livres ","time":"13/01/2026 09:13:52","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/6966370818ee6f52a701f2be)","time":"13/01/2026 09:14:00","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* https://cursos.ficv.edu.br/super_live_ficv/","time":"13/01/2026 09:14:05","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nConseguiu fazer a sua matricula?","time":"14/01/2026 08:18:57","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nrodolfo, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"14/01/2026 09:32:42"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"16/01/2026 09:04:34"},{"role":"client","text":"Sua sessão expirou!","time":"16/01/2026 09:06:35"}]$tag$, $tag$2026-01-13 08:41:47+00$tag$, FALSE, FALSE, 6.6, $tag$2026-03-01 16:46:57.607947+00$tag$, 7, 10, 5, 2, 9, 12, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$8e9d6569-d7b2-47a9-944f-80291e508741$tag$, $tag$2026011300023$tag$, $tag$EDIVAR BARROSO DA SILVA (5586999503810)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Bom dia","time":"13/01/2026 09:20:00"},{"role":"client","text":"🌟 Bom dia EDIVAR BARROSO DA SILVA! Que alegria ter você aqui com a gente! 🙌","time":"13/01/2026 09:20:02"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"13/01/2026 09:20:06"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"13/01/2026 09:20:10"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"13/01/2026 09:20:16"},{"role":"client","text":"Estudo a pós do novo testamento","time":"13/01/2026 09:20:30"},{"role":"client","text":"Ops, não consegui entender sua mensagem. 😕 \n\nPor favor, selecione  *a opção desejada*  no menu anterior.\n","time":"13/01/2026 09:20:31"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"13/01/2026 09:20:32"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"13/01/2026 09:20:46"},{"role":"client","text":"Olá! EDIVAR BARROSO DA SILVA!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"13/01/2026 09:20:47"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"13/01/2026 09:20:52"},{"role":"client","text":"Saber sobre os cursos","time":"13/01/2026 09:21:01"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"13/01/2026 09:21:05"},{"role":"client","text":"Graduação","time":"13/01/2026 09:21:17"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"13/01/2026 09:21:21"},{"role":"client","text":"Teologia (EAD)","time":"13/01/2026 09:21:36"},{"role":"client","text":"📚 A graduação EAD em Teologia é ideal para quem busca flexibilidade e profundidade bíblica onde estiver.\n✨ Estude no seu ritmo, com uma formação teológica séria e completa:\n 🧠 Cosmovisão Cristã\n 🔠 Grego e Hebraico\n 💻 Plataforma moderna e aulas dinâmicas\n 🤝 Mentoria, iniciação científica e prática ministerial\n","time":"13/01/2026 09:21:37"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"13/01/2026 09:21:41"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"13/01/2026 09:22:06"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"13/01/2026 09:22:07"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"13/01/2026 09:22:28"},{"role":"client","text":"Tem bacharel em Teologia EAD?","time":"13/01/2026 09:22:43"},{"role":"agent","text":"*Karina Pimentel:* A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"13/01/2026 09:22:59","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Bom dia","time":"13/01/2026 09:22:59"},{"role":"agent","text":"*Karina Pimentel:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$  431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"13/01/2026 09:23:16","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Eu já faço a pós do novo testamento","time":"13/01/2026 09:23:40"},{"role":"client","text":"Tem como os valores do curso EAD em bacharel em Teologia serem do mesmo valor?","time":"13/01/2026 09:24:16"},{"role":"client","text":"Valor que eu pago atualmente da pós?","time":"13/01/2026 09:24:52"},{"role":"agent","text":"*Karina Pimentel:* Benção!","time":"13/01/2026 09:25:02","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Para assim fazer os dois","time":"13/01/2026 09:25:11"},{"role":"agent","text":"*Karina Pimentel:* A Graduação seria outro curso, e teria um prazo de 3 anos.","time":"13/01/2026 09:25:43","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/696639dcf701a3607f01049f)","time":"13/01/2026 09:26:04"},{"role":"client","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/696639f738e5040cdc02e017)","time":"13/01/2026 09:26:31"},{"role":"client","text":"Moro em Domingos Mourão no Interior do Piauí","time":"13/01/2026 09:26:59"},{"role":"agent","text":"*Karina Pimentel:* Vou lhe enviar um formulário de solicitação de desconto ok!","time":"13/01/2026 09:33:17","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Para ser avaliado!","time":"13/01/2026 09:33:27","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:*  https://bit.ly/RequerimentodeDescontoFICV","time":"13/01/2026 09:33:48","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Ok","time":"13/01/2026 09:33:51"},{"role":"client","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/69663bbf31b02cbfd401f82d)","time":"13/01/2026 09:34:07"},{"role":"agent","text":"*Karina Pimentel:* No momento não oferecemos esse curso senhor Edivar!","time":"13/01/2026 09:34:59","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Ok","time":"13/01/2026 09:35:19"},{"role":"agent","text":"*Karina Pimentel:*  Espero ter atendido sua demanda. Caso tenha alguma outra dúvida ou solicitação, não hesite em entrar em contato novamente. Deus te abençoe. 😊","time":"13/01/2026 16:22:50","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nEDIVAR BARROSO DA SILVA, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"13/01/2026 16:22:52"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"13/01/2026 16:22:54"},{"role":"client","text":"EDIVAR BARROSO DA SILVA, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"13/01/2026 16:37:57"}]$tag$, $tag$2026-01-13 09:20:00+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 9, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$d8376d1c-a1d4-49ba-9300-bfc6b266c550$tag$, $tag$2026011300027$tag$, $tag$Elizabeth Baptista (5521985105325)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia Novo Testamento e quero mais informações.","time":"13/01/2026 09:35:33"},{"role":"client","text":"🌟 Bom dia Elizabeth Baptista! Que alegria ter você aqui com a gente! 🙌","time":"13/01/2026 09:35:34"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"13/01/2026 09:35:37"},{"role":"client","text":"Bom dia","time":"13/01/2026 09:35:38"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"13/01/2026 09:35:38"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"13/01/2026 09:35:41"},{"role":"client","text":"A paz do senhor Jesus","time":"13/01/2026 09:35:45"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"13/01/2026 09:35:45"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"13/01/2026 09:35:46"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"13/01/2026 09:35:51"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"13/01/2026 09:35:57"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"13/01/2026 09:35:57"},{"role":"client","text":"Sim, concordo","time":"13/01/2026 09:36:10"},{"role":"client","text":"✅ Obrigado, Elizabeth Baptista! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"13/01/2026 09:36:11"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"13/01/2026 09:36:14"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"13/01/2026 09:36:31"},{"role":"client","text":"Olá! Elizabeth Baptista!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"13/01/2026 09:36:32"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"13/01/2026 09:36:36"},{"role":"client","text":"Falar com um atendente","time":"13/01/2026 09:36:48"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"13/01/2026 09:36:48"},{"role":"client","text":"Gostaria pós Teologia do Novo Testamento","time":"13/01/2026 09:37:18"},{"role":"client","text":"Oi","time":"13/01/2026 09:40:34"},{"role":"client","text":"Oi","time":"13/01/2026 09:40:36"},{"role":"client","text":"Oi, já preenchi meus dados na página Teologia Novo Testamento e quero mais informações.","time":"13/01/2026 09:40:51"},{"role":"client","text":"Oi, já preenchi meus dados na página Teologia Novo Testamento e quero mais informações.","time":"13/01/2026 09:42:34"},{"role":"client","text":"Oi, já preenchi meus dados na página Teologia Novo Testamento e quero mais informações.","time":"13/01/2026 09:45:31"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"13/01/2026 09:47:38"},{"role":"agent","text":"*Karina Pimentel:*  *Pós-graduação em Teologia Bíblica e Exegética do Novo Testamento*\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 440h.\n\n*DISCIPLINAS*\nContamos com um total de 12 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"13/01/2026 09:48:17","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* \n O valor de investimento na Pós-graduação em Novo Testamento está em 16 mensalidades de *R$ 359,37.\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril!","time":"13/01/2026 09:49:10","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 20% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 287,50.\nVamos garantir a sua vaga? 😊","time":"13/01/2026 09:49:34","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"O que devo fazer para a inscrição","time":"13/01/2026 09:50:46"},{"role":"client","text":"Qdo inicia?","time":"13/01/2026 09:50:54"},{"role":"client","text":"Tenho interesse","time":"13/01/2026 09:52:34"},{"role":"client","text":"Esse curso precisa de ter conhecimento ou domínio do Grego???","time":"13/01/2026 10:00:31"},{"role":"client","text":"Tenho interesse","time":"13/01/2026 10:03:31"},{"role":"client","text":"O que devo fazer para a inscrição","time":"13/01/2026 10:03:32"},{"role":"client","text":"Esse curso precisa de ter conhecimento ou domínio do Grego???","time":"13/01/2026 10:03:32"},{"role":"client","text":"Oi","time":"13/01/2026 11:09:19"},{"role":"client","text":"Tem como me responder","time":"13/01/2026 11:10:05"},{"role":"agent","text":"*Karina Pimentel:* Não! ","time":"13/01/2026 11:11:22","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* - Teologia e exegética do novo testamento: Uma pós-graduação baseada nos seguintes diferenciais: Desenvolvida com objetivo de apresentar todo conteúdo dos livros do Novo Testamento, através de professores especialistas da área e com uma análise abrangente do contexto histórico, arqueológico e cultural da época\nUma oportunidade de se especializar com professores especialistas da área.\nAmpliar seu conhecimento da cultura do Antigo Oriente;\nCompreender textos complexos do Novo Testamento à luz da exegese bíblica;\nAmpliar sua capacidade de interpretação do Novo Testamento.","time":"13/01/2026 11:11:54","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Como fazer a inscrição","time":"13/01/2026 11:14:39"},{"